// Flatten the YouTube playlistItems response into one item per video.
const resp = items[0].json;
const vids = (resp.items || []).map(it => ({
  json: {
    video_id: it.contentDetails?.videoId || it.snippet?.resourceId?.videoId,
    title: it.snippet?.title || '',
    channel: it.snippet?.videoOwnerChannelTitle || it.snippet?.channelTitle || '',
    added_at: it.snippet?.publishedAt || new Date().toISOString(),
  }
})).filter(v => v.json.video_id);
return vids;

// Input: yt-helper response. Builds the Notion create-page body and the Gemini request body.
const v = $json;
const loopItem = $('Loop Videos').item.json;
const CATEGORIES = ["Homelab", "Home Automation", "AI", "Networking", "3D Printing", "Software Development", "Hardware", "Other"];

// --- Notion create body ---
const props = {
  'Name': { title: [{ text: { content: (v.title || 'Untitled').slice(0, 2000) } }] },
  'Video ID': { rich_text: [{ text: { content: v.video_id } }] },
  'Channel': { rich_text: [{ text: { content: (v.channel || '').slice(0, 2000) } }] },
  'Video URL': { url: `https://www.youtube.com/watch?v=${v.video_id}` },
  'Duration': { rich_text: [{ text: { content: v.duration_string || '' } }] },
  'Status': { select: { name: 'Processing' } },
  'Date Added': { date: { start: loopItem.added_at } },
};
if (v.upload_date) props['Upload Date'] = { date: { start: v.upload_date } };

const notion_create = {
  parent: { database_id: '97628e5e1e12481eb3541af829e2ebbe' },
  cover: { type: 'external', external: { url: v.thumbnail_url } },
  properties: props,
};

// --- Gemini body ---
const MAX_CHARS = 600000; // stay well under free-tier 250K TPM
let transcript = v.transcript || '';
let truncated = false;
if (transcript.length > MAX_CHARS) { transcript = transcript.slice(0, MAX_CHARS); truncated = true; }

const prompt = [
  'You are analyzing a YouTube video to build a structured knowledge-base entry.',
  '',
  `VIDEO TITLE: ${v.title}`,
  `CHANNEL: ${v.channel}`,
  '',
  'VIDEO DESCRIPTION (verbatim, may contain links):',
  v.description || '(no description)',
  '',
  'LINKS FOUND IN DESCRIPTION:',
  (v.description_links || []).join('\n') || '(none)',
  '',
  transcript
    ? 'FULL TRANSCRIPT' + (truncated ? ' (truncated)' : '') + ':\n' + transcript
    : 'NO TRANSCRIPT AVAILABLE. Base your analysis on the title and description only, and say so in the summary.',
  '',
  'INSTRUCTIONS:',
  '1. summary: 2-4 paragraph summary of what the video covers and its key takeaways.',
  '2. key_points: 4-10 concise bullet points of the most important information.',
  `3. category: exactly one of: ${CATEGORIES.join(', ')}.`,
  '4. topics: 2-8 short tags (1-3 words each) for filtering, e.g. "Docker", "Proxmox", "3D Printing".',
  '5. items: every distinct product, GitHub repo, tool, service, or article DISCUSSED in the video.',
  '   For each item: name; type (repo|product|service|article|other); context (one sentence on how it was discussed);',
  '   url: if one of the description links clearly belongs to this item, use that link EXACTLY as written.',
  '   Otherwise provide the official homepage or repository URL if you are confident you know it; set url to null if unsure.',
  '   url_source: "description" if taken from the description links, "model" if from your knowledge, "none" if null.',
  'Return ONLY valid JSON matching the schema. No markdown fences.',
].join('\n');

const gemini_body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: {
    temperature: 0.3,
    response_mime_type: 'application/json',
    response_schema: {
      type: 'OBJECT',
      properties: {
        summary: { type: 'STRING' },
        key_points: { type: 'ARRAY', items: { type: 'STRING' } },
        category: { type: 'STRING' },
        topics: { type: 'ARRAY', items: { type: 'STRING' } },
        items: {
          type: 'ARRAY',
          items: {
            type: 'OBJECT',
            properties: {
              name: { type: 'STRING' },
              type: { type: 'STRING' },
              context: { type: 'STRING' },
              url: { type: 'STRING', nullable: true },
              url_source: { type: 'STRING' },
            },
            required: ['name', 'type', 'context'],
          },
        },
      },
      required: ['summary', 'key_points', 'category', 'topics', 'items'],
    },
  },
};

return [{ json: { notion_create, gemini_body, video: v } }];

// Parse Gemini output, resolve repo URLs via GitHub search, verify all URLs with HEAD checks.
const resp = $json;
let text = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
text = text.replace(/^```json\s*/i, '').replace(/^```\s*/, '').replace(/```\s*$/, '').trim();

let parsed;
try { parsed = JSON.parse(text); }
catch (e) { throw new Error('Gemini returned unparseable JSON: ' + text.slice(0, 300)); }

const video = $('Prepare Requests').item.json.video;
const descLinks = new Set(video.description_links || []);

async function head(url) {
  try {
    await this.helpers.httpRequest({ method: 'HEAD', url, timeout: 10000 });
    return true;
  } catch (e) {
    // Some servers reject HEAD; try a lightweight GET before declaring dead
    try {
      await this.helpers.httpRequest({ method: 'GET', url, timeout: 10000,
        headers: { 'Range': 'bytes=0-256' } });
      return true;
    } catch (e2) { return false; }
  }
}

async function githubSearch(name, context) {
  try {
    const q = encodeURIComponent(name);
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.github.com/search/repositories?q=${q}&per_page=1`,
      headers: { 'User-Agent': 'yt-pipeline', 'Accept': 'application/vnd.github+json' },
      timeout: 15000,
    });
    const hit = (typeof r === 'string' ? JSON.parse(r) : r)?.items?.[0];
    return hit?.html_url || null;
  } catch (e) { return null; }
}

const out = [];
let hasUnverified = false;

for (const item of (parsed.items || [])) {
  let url = item.url || null;
  let verified = false;
  let source = item.url_source || (url ? 'model' : 'none');

  if (url && descLinks.has(url)) {
    verified = true; source = 'description';           // creator-provided: trusted
  } else {
    if (!url && (item.type === 'repo')) {
      url = await githubSearch.call(this, item.name, item.context);
      if (url) source = 'github-search';
    }
    if (url) verified = await head.call(this, url);
  }

  if (!url || !verified) {
    hasUnverified = true;
    if (!url) url = 'https://www.google.com/search?q=' + encodeURIComponent(item.name);
  }
  out.push({ name: item.name, type: item.type, context: item.context, url, verified, source });
}

return [{ json: {
  page_id: $('Create Notion Entry').item.json.id,
  video,
  summary: parsed.summary || '',
  key_points: parsed.key_points || [],
  category: parsed.category || 'Other',
  topics: parsed.topics || [],
  resolved_items: out,
  has_unverified: hasUnverified,
}}];

// Build the Notion properties patch and the page-body block batches.
const d = $json;
const CATEGORIES = ["Homelab", "Home Automation", "AI", "Networking", "3D Printing", "Software Development", "Hardware", "Other"];
const chunk = (s, n = 2000) => { const o = []; for (let i = 0; i < (s || '').length; i += n) o.push(s.slice(i, i + n)); return o; };
const para = (t) => ({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: t } }] } });
const h2 = (t) => ({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: t } }] } });
const bullet = (rich) => ({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: rich } });
const txt = (t, link = null) => ({ type: 'text', text: { content: t, ...(link ? { link: { url: link } } : {}) } });

const properties = {
  'Status': { select: { name: 'Done' } },
  'Category': { select: { name: CATEGORIES.includes(d.category) ? d.category : 'Other' } },
  'Topics': { multi_select: (d.topics || []).slice(0, 10).map(t => ({ name: String(t).slice(0, 100) })) },
  'Has Unverified Links': { checkbox: !!d.has_unverified },
};

const main = [];
main.push({ object: 'block', type: 'video',
  video: { type: 'external', external: { url: `https://www.youtube.com/watch?v=${d.video.video_id}` } } });

main.push(h2('Summary'));
chunk(d.summary).forEach(c => main.push(para(c)));

main.push(h2('Key Points'));
(d.key_points || []).forEach(k => main.push(bullet([txt(String(k).slice(0, 2000))])));

main.push(h2('Items & Links'));
if ((d.resolved_items || []).length === 0) main.push(para('No specific items identified.'));
(d.resolved_items || []).forEach(it => {
  const rich = [];
  if (it.verified) {
    rich.push(txt(it.name, it.url));
    rich.push(txt(` (${it.type}) - ${it.context}`.slice(0, 1800)));
  } else {
    rich.push(txt(`\u26A0\uFE0F ${it.name} (unverified)`, it.url));
    rich.push(txt(` (${it.type}) - ${it.context}`.slice(0, 1800)));
  }
  main.push(bullet(rich));
});

// Description toggle (children nested in same payload)
const descChunks = chunk(d.video.description || '');
if (descChunks.length) {
  main.push({ object: 'block', type: 'toggle',
    toggle: { rich_text: [txt('Full Description')], children: descChunks.slice(0, 80).map(para) } });
}

// Batches: main blocks first, then transcript in toggles of up to 80 chunks each
const batches = [{ page_id: d.page_id, children: main }];
const tChunks = chunk(d.video.transcript || '');
if (tChunks.length === 0) {
  batches[0].children.push(para('No transcript available for this video.'));
} else {
  const per = 80;
  const nTog = Math.ceil(tChunks.length / per);
  for (let i = 0; i < nTog; i++) {
    const label = nTog > 1 ? `Full Transcript (${i + 1}/${nTog})` : 'Full Transcript';
    batches.push({ page_id: d.page_id, children: [{ object: 'block', type: 'toggle',
      toggle: { rich_text: [txt(label)], children: tChunks.slice(i * per, (i + 1) * per).map(para) } }] });
  }
}

return [{ json: { page_id: d.page_id, properties, batches } }];
